  1→import { ORPCError } from "@orpc/server";
  2→import { member, organization, session } from "@rudel/sql-schema";
  3→import { and, eq } from "drizzle-orm";
  4→import { getClickhouse } from "./clickhouse.js";
  5→import { db } from "./db.js";
  6→import { analyticsRouter } from "./handlers/analytics/index.js";
  7→import { ingestSession } from "./ingest.js";
  8→import { authMiddleware, os } from "./middleware.js";
  9→import {
 10→	deleteOrgSessions,
 11→	getOrgSessionCount,
 12→	migrateOrgSessions,
 13→} from "./services/org-session.service.js";
 14→
 15→const health = os.health.handler(() => {
 16→	return {
 17→		status: "ok" as const,
 18→		timestamp: Date.now(),
 19→	};
 20→});
 21→
 22→const me = os.me.use(authMiddleware).handler(({ context }) => {
 23→	return {
 24→		id: context.user.id,
 25→		email: context.user.email,
 26→		name: context.user.name,
 27→		image: context.user.image ?? null,
 28→		activeOrganizationId:
 29→			((context.session as Record<string, unknown>).activeOrganizationId as
 30→				| string
 31→				| null) ?? null,
 32→	};
 33→});
 34→
 35→const listMyOrganizations = os.listMyOrganizations
 36→	.use(authMiddleware)
 37→	.handler(async ({ context }) => {
 38→		const memberships = await db
 39→			.select({
 40→				id: organization.id,
 41→				name: organization.name,
 42→				slug: organization.slug,
 43→				logo: organization.logo,
 44→			})
 45→			.from(member)
 46→			.innerJoin(organization, eq(member.organizationId, organization.id))
 47→			.where(eq(member.userId, context.user.id));
 48→
 49→		return memberships.map((m) => ({
 50→			id: m.id,
 51→			name: m.name,
 52→			slug: m.slug,
 53→			logo: m.logo ?? null,
 54→		}));
 55→	});
 56→
 57→const ingestSessionHandler = os.ingestSession
 58→	.use(authMiddleware)
 59→	.handler(async ({ input, context }) => {
 60→		const orgId =
 61→			input.organizationId ??
 62→			((context.session as Record<string, unknown>).activeOrganizationId as
 63→				| string
 64→				| null) ??
 65→			context.user.id;
 66→
 67→		if (input.organizationId) {
 68→			const membership = await db
 69→				.select({ id: member.id })
 70→				.from(member)
 71→				.where(
 72→					and(
 73→						eq(member.organizationId, input.organizationId),
 74→						eq(member.userId, context.user.id),
 75→					),
 76→				)
 77→				.limit(1);
 78→
 79→			if (membership.length === 0) {
 80→				throw new ORPCError("FORBIDDEN", {
 81→					message: "Not a member of the specified organization",
 82→				});
 83→			}
 84→		}
 85→
 86→		await ingestSession(getClickhouse(), input, {
 87→			userId: context.user.id,
 88→			organizationId: orgId,
 89→		});
 90→
 91→		return {
 92→			success: true as const,
 93→			sessionId: input.sessionId,
 94→		};
 95→	});
 96→
 97→const getOrganizationSessionCount = os.getOrganizationSessionCount
 98→	.use(authMiddleware)
 99→	.handler(async ({ input, context }) => {
100→		const membership = await db
101→			.select({ id: member.id })
102→			.from(member)
103→			.where(
104→				and(
105→					eq(member.organizationId, input.organizationId),
106→					eq(member.userId, context.user.id),
107→				),
108→			)
109→			.limit(1);
110→
111→		if (membership.length === 0) {
112→			throw new ORPCError("FORBIDDEN", {
113→				message: "Not a member of this organization",
114→			});
115→		}
116→
117→		const count = await getOrgSessionCount(input.organizationId);
118→		return { count };
119→	});
120→
121→const deleteOrganization = os.deleteOrganization
122→	.use(authMiddleware)
123→	.handler(async ({ input, context }) => {
124→		// Check user has more than one org
125→		const memberships = await db
126→			.select({ organizationId: member.organizationId })
127→			.from(member)
128→			.where(eq(member.userId, context.user.id));
129→
130→		if (memberships.length <= 1) {
131→			throw new ORPCError("BAD_REQUEST", {
132→				message: "Cannot delete your only organization",
133→			});
134→		}
135→
136→		// Verify user is owner of the target org
137→		const ownership = await db
138→			.select({ id: member.id })
139→			.from(member)
140→			.where(
141→				and(
142→					eq(member.organizationId, input.organizationId),
143→					eq(member.userId, context.user.id),
144→					eq(member.role, "owner"),
145→				),
146→			)
147→			.limit(1);
148→
149→		if (ownership.length === 0) {
150→			throw new ORPCError("FORBIDDEN", {
151→				message: "Only the organization owner can delete it",
152→			});
153→		}
154→
155→		if (input.migrateSessionsTo) {
156→			if (input.migrateSessionsTo === input.organizationId) {
157→				throw new ORPCError("BAD_REQUEST", {
158→					message: "Cannot migrate sessions to the same organization",
159→				});
160→			}
161→
162→			// Verify user is a member of the target org
163→			const targetMembership = await db
164→				.select({ id: member.id })
165→				.from(member)
166→				.where(
167→					and(
168→						eq(member.organizationId, input.migrateSessionsTo),
169→						eq(member.userId, context.user.id),
170→					),
171→				)
172→				.limit(1);
173→
174→			if (targetMembership.length === 0) {
175→				throw new ORPCError("FORBIDDEN", {
176→					message: "Not a member of the target organization",
177→				});
178→			}
179→
180→			await migrateOrgSessions(input.organizationId, input.migrateSessionsTo);
181→		} else {
182→			await deleteOrgSessions(input.organizationId);
183→		}
184→
185→		// Delete the organization from Postgres (cascade handles member + invitation)
186→		await db
187→			.delete(organization)
188→			.where(eq(organization.id, input.organizationId));
189→
190→		// Clear activeOrganizationId on user sessions that reference the deleted org
191→		await db
192→			.update(session)
193→			.set({ activeOrganizationId: null })
194→			.where(eq(session.activeOrganizationId, input.organizationId));
195→
196→		return { success: true as const };
197→	});
198→
199→export const router = os.router({
200→	health,
201→	me,
202→	listMyOrganizations,
203→	ingestSession: ingestSessionHandler,
204→	getOrganizationSessionCount,
205→	deleteOrganization,
206→	analytics: analyticsRouter,
207→});
