 1→import type { IngestSessionInput } from "@rudel/api-routes";
 2→import {
 3→	type Ingestor,
 4→	ingestRudelClaudeSessions,
 5→	type RudelClaudeSessionsRow,
 6→} from "@rudel/ch-schema/generated";
 7→
 8→interface IngestContext {
 9→	userId: string;
10→	organizationId: string;
11→}
12→
13→export function extractTimestampRange(content: string): {
14→	sessionDate: string;
15→	lastInteractionDate: string;
16→} | null {
17→	let min: string | null = null;
18→	let max: string | null = null;
19→
20→	for (const line of content.split("\n")) {
21→		if (!line) continue;
22→		let parsed: { type?: string; timestamp?: string };
23→		try {
24→			parsed = JSON.parse(line);
25→		} catch {
26→			continue;
27→		}
28→		if (
29→			(parsed.type === "user" || parsed.type === "assistant") &&
30→			parsed.timestamp
31→		) {
32→			const ts = parsed.timestamp;
33→			if (!min || ts < min) min = ts;
34→			if (!max || ts > max) max = ts;
35→		}
36→	}
37→
38→	if (!min || !max) return null;
39→
40→	return { sessionDate: min, lastInteractionDate: max };
41→}
42→
43→function toClickHouseDateTime(isoString: string): string {
44→	return isoString.replace("T", " ").replace("Z", "").replace(/\+.*$/, "");
45→}
46→
47→export function buildSessionRow(
48→	input: IngestSessionInput,
49→	context: IngestContext,
50→): RudelClaudeSessionsRow {
51→	const now = new Date().toISOString().replace("Z", "");
52→
53→	const subagents: Record<string, string> = {};
54→	if (input.subagents) {
55→		for (const sub of input.subagents) {
56→			subagents[sub.agentId] = sub.content;
57→		}
58→	}
59→
60→	const timestamps = extractTimestampRange(input.content);
61→
62→	return {
63→		session_date: timestamps
64→			? toClickHouseDateTime(timestamps.sessionDate)
65→			: now,
66→		last_interaction_date: timestamps
67→			? toClickHouseDateTime(timestamps.lastInteractionDate)
68→			: now,
69→		session_id: input.sessionId,
70→		organization_id: context.organizationId,
71→		project_path: input.projectPath,
72→		repository: input.repository ?? null,
73→		content: input.content,
74→		subagents,
75→		ingested_at: now,
76→		user_id: context.userId,
77→		git_branch: input.gitBranch ?? null,
78→		git_sha: input.gitSha ?? null,
79→		tag: input.tag ?? null,
80→	};
81→}
82→
83→export async function ingestSession(
84→	ingestor: Ingestor,
85→	input: IngestSessionInput,
86→	context: IngestContext,
87→): Promise<void> {
88→	const row = buildSessionRow(input, context);
89→	await ingestRudelClaudeSessions(ingestor, [row]);
90→}
91→

 1→import { createClient } from "@clickhouse/client-web";
 2→
 3→export interface ClickHouseExecutor {
 4→	execute(sql: string): Promise<void>;
 5→	query<T>(sql: string): Promise<T[]>;
 6→	insert(params: { table: string; values: object[] }): Promise<void>;
 7→}
 8→
 9→export function createClickHouseExecutor(config: {
10→	url: string;
11→	username?: string;
12→	password?: string;
13→	database?: string;
14→}): ClickHouseExecutor {
15→	const client = createClient({
16→		url: config.url,
17→		username: config.username,
18→		password: config.password,
19→		database: config.database,
20→		clickhouse_settings: {
21→			wait_end_of_query: 1,
22→		},
23→	});
24→	return {
25→		async execute(sql) {
26→			await client.command({ query: sql });
27→		},
28→		async query<T>(sql: string): Promise<T[]> {
29→			const result = await client.query({
30→				query: sql,
31→				format: "JSONEachRow",
32→			});
33→			return result.json();
34→		},
35→		async insert(params) {
36→			// Use command() with FORMAT JSONEachRow instead of client.insert()
37→			// because ClickHouse Cloud's @clickhouse/client insert() silently drops data.
38→			const rows = params.values.map((r) => JSON.stringify(r)).join("\n");
39→			await client.command({
40→				query: `INSERT INTO ${params.table} SETTINGS async_insert=0 FORMAT JSONEachRow ${rows}`,
41→			});
42→		},
43→	};
44→}
45→
46→let _clickhouse: ClickHouseExecutor | null = null;
47→
48→export function getClickhouse(): ClickHouseExecutor {
49→	if (!_clickhouse) {
50→		const executor = createClickHouseExecutor({
51→			url: process.env.CLICKHOUSE_URL || "http://localhost:8123",
52→			username:
53→				process.env.CLICKHOUSE_USERNAME ||
54→				process.env.CLICKHOUSE_USER ||
55→				"default",
56→			password: process.env.CLICKHOUSE_PASSWORD || "",
57→			database: "default",
58→		});
59→		const maxRetries = 3;
60→		_clickhouse = {
61→			...executor,
62→			async insert(params) {
63→				for (let attempt = 0; attempt < maxRetries; attempt++) {
64→					try {
65→						return await executor.insert(params);
66→					} catch (error) {
67→						// Retry on INSERT race conditions (ClickHouse code 236)
68→						if (attempt === maxRetries - 1) throw error;
69→						await new Promise((r) => setTimeout(r, 100 * (attempt + 1)));
70→					}
71→				}
72→			},
73→		};
74→	}
75→	return _clickhouse;
76→}
77→
78→export function escapeString(value: string): string {
79→	return value.replace(/'/g, "\\'");
80→}
81→
82→export function buildDateFilter(days: number, column = "session_date"): string {
83→	return `${column} >= now64(3) - INTERVAL ${Number(days)} DAY AND ${column} <= now64(3)`;
84→}
85→
86→export async function queryClickhouse<T>(sql: string): Promise<T[]> {
